async (params, browser) => {
  // Open page
  await browser.open(`${params.label_url}`)

  // Wait for content
  await browser.waitForSelector('h1, [class*="title"], .profile', 15000)

  // Let page render
  await browser.wait(2500)

  // Scroll for more
  await browser.scroll({ direction: 'down', amount: 1000 })

  await browser.wait(2000)

  // Extract data
  const page_data = await browser.evaluate(`const name = document.querySelector('h1')?.textContent?.trim()||''; const profile = document.querySelector('.profile, [class*="Profile"]')?.textContent?.trim()?.substring(0,1000)||''; const releases = Array.from(document.querySelectorAll('table tbody tr')).slice(0,30).map(row => { const t = row.querySelector('a[href*="/release/"], a[href*="/master/"]'); const cat = row.querySelector('td:first-child')?.textContent?.trim()||''; const artist = row.querySelector('td:nth-child(2) a')?.textContent?.trim()||''; return { title: t?t.textContent.trim():'', catalog: cat, artist }; }).filter(r=>r.title); return { name, profile, catalog: releases, url: window.location.href }`)

  return page_data
}
